import subprocessfrom criresviz.common import SKYfrom criresviz.skycalc.defaults import (    DEFAULT_SKYCALC_PARAMETERS,)'''################################################################################################################################# Help Functions ###################################################################################################################################'''def write_input(filename, parameters):    with open(filename, "w") as f:        for key, value in parameters.items():            f.write(f"{key:<16}: {value}\n")                                      def run_skycalc(input_file, output_file):    subprocess.run(        [            "skycalc_cli",            "-i",            str(input_file),            "-o",            str(output_file),        ],        check=True,    )                '''####################################################################################################################################### MAIN #######################################################################################################################################'''        def compute_sky(**kwargs):    """    Generate a sky model with SkyCalc.    Parameters    ----------    **kwargs        SkyCalc parameters to override.    """    parameters = DEFAULT_SKYCALC_PARAMETERS.copy()    for key, value in kwargs.items():        if key not in DEFAULT_SKYCALC_PARAMETERS:            raise KeyError(                f"Unknown SkyCalc parameter: '{key}'"            )        parameters[key] = value    SKY.mkdir(        parents=True,        exist_ok=True,    )    input_file = SKY / "default.input"    output_file = SKY / "default.fits"    write_input(        input_file,        parameters,    )    print("Running SkyCalc...")    run_skycalc(        input_file,        output_file,    )    print(f"Saved {output_file}")    return output_file            def main():    compute_sky()    if __name__ == "__main__":    main()